{
  "_comment": "Partner Center offer configuration — Authorizations tab",
  "authorizations": [
    {
      "principalId": "<MSP_TIER1_GROUP_OID>",
      "principalIdDisplayName": "Contoso MSP Support - Read Only",
      "roleDefinitionId": "acdd72a7-3385-48ef-bd42-f606fba81ae7",
      "delegatedRoleDefinitionIds": []
    },
    {
      "principalId": "<MSP_ENGINEERS_GROUP_OID>",
      "principalIdDisplayName": "Contoso MSP Engineers",
      "roleDefinitionId": "b24988ac-6180-42a0-ab88-20f7382dd24c",
      "delegatedRoleDefinitionIds": []
    }
  ],
  "eligibleAuthorizations": [
    {
      "principalId": "<MSP_SECURITY_GROUP_OID>",
      "principalIdDisplayName": "Contoso MSP Security Team (JIT)",
      "roleDefinitionId": "8e3af657-a8ff-443c-a75c-2fe8c4bcb635",
      "justInTimeAccessPolicy": {
        "multiFactorAuthProvider": "Azure",
        "maximumActivationDuration": "PT4H",
        "managedByTenantApprovers": [
          {
            "principalId": "<MSP_CAB_GROUP_OID>",
            "principalIdDisplayName": "Contoso MSP Change Advisory Board"
          }
        ]
      }
    }
  ],
  "_note": "Plans can be public (any Azure customer) or private (specific tenant IDs). Private plans require listing the customer tenant IDs explicitly in Partner Center."
}

// lighthouse-delegation.bicep — deploy at subscription scope (targetScope required)
targetScope = 'subscription'

@description('MSP managing tenant ID')
param mspTenantId string

@description('Offer display name')
param offerName string = 'Contoso MSP Managed Services'

@description('Reader group OID in MSP tenant')
param readGroupOid string

@description('Engineers group OID in MSP tenant')
param engineerGroupOid string

var readerRole       = 'acdd72a7-3385-48ef-bd42-f606fba81ae7'
var contributorRole  = 'b24988ac-6180-42a0-ab88-20f7382dd24c'
var policyContrib    = '36243c78-bf99-498c-9df9-86d9f8d28608'

resource definition 'Microsoft.ManagedServices/registrationDefinitions@2022-10-01' = {
  name: guid(subscription().id, offerName)
  properties: {
    registrationDefinitionName: offerName
    description: 'Contoso MSP full-management delegation'
    managedByTenantId: mspTenantId
    authorizations: [
      {
        principalId: readGroupOid
        principalIdDisplayName: 'MSP Read-Only Team'
        roleDefinitionId: readerRole
      }
      {
        principalId: engineerGroupOid
        principalIdDisplayName: 'MSP Engineers'
        roleDefinitionId: contributorRole
      }
      {
        principalId: engineerGroupOid
        principalIdDisplayName: 'MSP Engineers (Policy)'
        roleDefinitionId: policyContrib
      }
    ]
  }
}

resource assignment 'Microsoft.ManagedServices/registrationAssignments@2022-10-01' = {
  name: guid(subscription().id, offerName, 'assign')
  properties: {
    registrationDefinitionId: definition.id
  }
}

{
  "_comment": "Policy definition: DeployIfNotExists Lighthouse delegation on all subscriptions",
  "mode": "All",
  "policyRule": {
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Resources/subscriptions"},
        {"not": {"field": "tags['excluded-from-lighthouse']", "equals": "true"}}
      ]
    },
    "then": {
      "effect": "deployIfNotExists",
      "details": {
        "type": "Microsoft.ManagedServices/registrationAssignments",
        "existenceCondition": {
          "field": "Microsoft.ManagedServices/registrationAssignments/registrationDefinitionId",
          "contains": "[parameters('mspDefinitionGuid')]"
        },
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/8e3af657-a8ff-443c-a75c-2fe8c4bcb635"
        ],
        "deploymentScope": "subscription",
        "deployment": {
          "location": "eastus",
          "properties": {
            "mode": "Incremental",
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2018-05-01/subscriptionDeploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "resources": [
                {
                  "type": "Microsoft.ManagedServices/registrationDefinitions",
                  "apiVersion": "2022-10-01",
                  "name": "[parameters('definitionName')]",
                  "properties": {
                    "registrationDefinitionName": "Central IT Delegation",
                    "managedByTenantId": "[parameters('managingTenantId')]",
                    "authorizations": "[parameters('authorizations')]"
                  }
                }
              ]
            },
            "parameters": {
              "definitionName": {"value": "[parameters('mspDefinitionGuid')]"},
              "managingTenantId": {"value": "[parameters('managingTenantId')]"},
              "authorizations": {"value": "[parameters('authorizations')]"}
            }
          }
        }
      }
    }
  }
}
